import copy

def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    bg = grid[0][0]
    result = copy.deepcopy(grid)
    ones = set()
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 1:
                ones.add((r, c))
    visited = set()
    crosses = []
    for r, c in ones:
        if (r,c) in visited:
            continue
        comp = []
        queue = [(r,c)]
        visited.add((r,c))
        while queue:
            cr, cc = queue.pop(0)
            comp.append((cr, cc))
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = cr+dr, cc+dc
                if (nr, nc) in ones and (nr, nc) not in visited:
                    visited.add((nr, nc))
                    queue.append((nr, nc))
        crosses.append(comp)
    for cross in crosses:
        cross_set = set(cross)
        min_r = min(r for r,c in cross)
        max_r = max(r for r,c in cross)
        min_c = min(c for r,c in cross)
        max_c = max(c for r,c in cross)
        tail_pixels = []
        for r, c in cross:
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < rows and 0 <= nc < cols and (nr,nc) not in cross_set and grid[nr][nc] != bg and grid[nr][nc] != 1:
                    tail_pixels.append((nr, nc, grid[nr][nc]))
        if not tail_pixels:
            continue
        if all(r > max_r for r,c,v in tail_pixels):
            direction = (1, 0)
        elif all(r < min_r for r,c,v in tail_pixels):
            direction = (-1, 0)
        elif all(c > max_c for r,c,v in tail_pixels):
            direction = (0, 1)
        elif all(c < min_c for r,c,v in tail_pixels):
            direction = (0, -1)
        else:
            continue
        dr, dc = direction
        if dr != 0:
            tail_col_set = sorted(set(c for r,c,v in tail_pixels))
            pattern = []
            start_row = max_r + 1 if dr == 1 else min_r - 1
            r = start_row
            while 0 <= r < rows:
                row_vals = {}
                all_bg = True
                for c in tail_col_set:
                    if grid[r][c] != bg:
                        row_vals[c] = grid[r][c]
                        all_bg = False
                if all_bg:
                    break
                pattern.append(row_vals)
                r += dr
            if not pattern:
                continue
            period = len(pattern)
            for p in range(1, len(pattern)):
                valid = True
                for i in range(len(pattern)):
                    if pattern[i] != pattern[i % p]:
                        valid = False
                        break
                if valid:
                    period = p
                    break
            base_pattern = pattern[:period]
            tail_end = start_row + (len(pattern) - 1) * dr
            r = tail_end + dr
            idx = len(pattern) % period
            while 0 <= r < rows:
                row_pattern = base_pattern[idx % period]
                for c, v in row_pattern.items():
                    result[r][c] = v
                r += dr
                idx += 1
        else:
            tail_row_set = sorted(set(r for r,c,v in tail_pixels))
            pattern = []
            start_col = max_c + 1 if dc == 1 else min_c - 1
            c = start_col
            while 0 <= c < cols:
                col_vals = {}
                all_bg = True
                for r in tail_row_set:
                    if grid[r][c] != bg:
                        col_vals[r] = grid[r][c]
                        all_bg = False
                if all_bg:
                    break
                pattern.append(col_vals)
                c += dc
            if not pattern:
                continue
            period = len(pattern)
            for p in range(1, len(pattern)):
                valid = True
                for i in range(len(pattern)):
                    if pattern[i] != pattern[i % p]:
                        valid = False
                        break
                if valid:
                    period = p
                    break
            base_pattern = pattern[:period]
            tail_end = start_col + (len(pattern) - 1) * dc
            c = tail_end + dc
            idx = len(pattern) % period
            while 0 <= c < cols:
                col_pattern = base_pattern[idx % period]
                for r, v in col_pattern.items():
                    result[r][c] = v
                c += dc
                idx += 1
    return result

