from collections import Counter

def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    flat = [v for row in grid for v in row]
    bg = Counter(flat).most_common(1)[0][0]
    rects = []
    found_rect_cells = set()
    for r in range(rows):
        for c in range(cols):
            if (r,c) in found_rect_cells:
                continue
            if grid[r][c] != bg:
                color = grid[r][c]
                if r > 0 and grid[r-1][c] == color:
                    continue
                if c > 0 and grid[r][c-1] == color:
                    continue
                w = 0
                while c + w < cols and grid[r][c+w] == color:
                    w += 1
                h = 0
                valid = True
                while r + h < rows and valid:
                    for dc in range(w):
                        if grid[r+h][c+dc] != color:
                            valid = False
                            break
                    if valid:
                        h += 1
                if w >= 5 and h >= 5:
                    rects.append((r, r+h, c, c+w, color))
                    for rr in range(r, r+h):
                        for cc in range(c, c+w):
                            found_rect_cells.add((rr, cc))
    if not rects:
        return grid
    min_r = min(r1 for r1,r2,c1,c2,_ in rects) - 1
    max_r = max(r2 for r1,r2,c1,c2,_ in rects) + 1
    min_c = min(c1 for r1,r2,c1,c2,_ in rects) - 1
    max_c = max(c2 for r1,r2,c1,c2,_ in rects) + 1
    min_r = max(0, min_r)
    max_r = min(rows, max_r)
    min_c = max(0, min_c)
    max_c = min(cols, max_c)
    rect_area = set()
    for r in range(min_r, max_r):
        for c in range(min_c, max_c):
            rect_area.add((r, c))
    color_pixels = {}
    for r in range(rows):
        for c in range(cols):
            if (r,c) not in rect_area and grid[r][c] != bg:
                color = grid[r][c]
                if color not in color_pixels:
                    color_pixels[color] = []
                color_pixels[color].append((r, c))
    patterns = {}
    for color, pixels in color_pixels.items():
        if not pixels:
            continue
        pixel_set = set(pixels)
        visited = set()
        for pr, pc in pixels:
            if (pr, pc) in visited:
                continue
            comp = []
            queue = [(pr, pc)]
            visited.add((pr, pc))
            while queue:
                cr, cc = queue.pop(0)
                comp.append((cr, cc))
                for dr in range(-2, 3):
                    for dc in range(-2, 3):
                        if dr == 0 and dc == 0:
                            continue
                        nr, nc = cr+dr, cc+dc
                        if (nr, nc) in pixel_set and (nr, nc) not in visited:
                            visited.add((nr, nc))
                            queue.append((nr, nc))
            min_pr = min(r for r,c in comp)
            min_pc = min(c for r,c in comp)
            max_pr = max(r for r,c in comp)
            max_pc = max(c for r,c in comp)
            h = max_pr - min_pr + 1
            w = max_pc - min_pc + 1
            if h <= 3 and w <= 3:
                pat = [[bg]*3 for _ in range(3)]
                for pr2, pc2 in comp:
                    pat[pr2-min_pr][pc2-min_pc] = color
                patterns[color] = pat
    out_h = max_r - min_r
    out_w = max_c - min_c
    result = [[bg]*out_w for _ in range(out_h)]
    for r in range(min_r, max_r):
        for c in range(min_c, max_c):
            result[r-min_r][c-min_c] = grid[r][c]
    for r1, r2, c1, c2, color in rects:
        if color not in patterns:
            continue
        pat = patterns[color]
        ir1 = r1 + 1
        ic1 = c1 + 1
        for pr in range(3):
            for pc in range(3):
                r = ir1 + pr - min_r
                c = ic1 + pc - min_c
                if 0 <= r < out_h and 0 <= c < out_w:
                    if pat[pr][pc] == color:
                        result[r][c] = bg
                    else:
                        result[r][c] = color
    return result

