from collections import Counter, defaultdict

def normalize_shape(cells):
    cells = [(r, c) for r, c in cells]
    transforms = []
    for flip in [False, True]:
        pts = cells[:]
        if flip:
            pts = [(-r, c) for r, c in pts]
        for rot in range(4):
            mr = min(r for r, c in pts)
            mc = min(c for r, c in pts)
            normalized = tuple(sorted((r - mr, c - mc) for r, c in pts))
            transforms.append(normalized)
            pts = [(c, -r) for r, c in pts]
    return min(transforms)

def find_components(pixel_set):
    visited = set()
    components = []
    for r, c in pixel_set:
        if (r,c) in visited:
            continue
        comp = []
        queue = [(r,c)]
        visited.add((r,c))
        while queue:
            cr, cc = queue.pop(0)
            comp.append((cr, cc))
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = cr+dr, cc+dc
                if (nr, nc) in pixel_set and (nr, nc) not in visited:
                    visited.add((nr, nc))
                    queue.append((nr, nc))
        components.append(comp)
    return components

def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
