        positions = [(r,c) for r in range(rows) for c in range(cols) if grid[r][c] == color]
        if len(positions) < 20:
            continue
        min_r = min(r for r,c in positions)
        max_r = max(r for r,c in positions)
        min_c = min(c for r,c in positions)
        max_c = max(c for r,c in positions)
        is_border = True
        for c2 in range(min_c, max_c+1):
            if grid[min_r][c2] != color or grid[max_r][c2] != color:
                is_border = False
                break
        if is_border:
            for r2 in range(min_r, max_r+1):
                if grid[r2][min_c] != color or grid[r2][max_c] != color:
                    is_border = False
                    break
        if is_border:
            rect_color = color
            rect_area = (min_r, max_r, min_c, max_c)
            break
    if rect_color is None:
        return grid
    min_r, max_r, min_c, max_c = rect_area
