def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    bg = grid[0][0]
    visited = set()
    components = []
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] != bg and (r,c) not in visited:
                comp = []
                queue = [(r,c)]
                visited.add((r,c))
                while queue:
                    cr, cc = queue.pop(0)
                    comp.append((cr, cc, grid[cr][cc]))
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < rows and 0 <= nc < cols and (nr,nc) not in visited and grid[nr][nc] != bg:
                            visited.add((nr,nc))
                            queue.append((nr,nc))
                components.append(comp)
    singles = [c for c in components if len(c) == 1]
    shapes = [c for c in components if len(c) > 1]
    target_map = {}
    for s in singles:
        r, c, v = s[0]
        target_map[v] = (r, c)
    result = [[bg]*cols for _ in range(rows)]
    for s in singles:
        r, c, v = s[0]
        result[r][c] = v
    for shape in shapes:
        color_counts = Counter(v for r,c,v in shape)
        special = min(color_counts, key=color_counts.get)
        special_pos = [(r,c) for r,c,v in shape if v == special]
        sr, sc = special_pos[0]
        target = target_map.get(special)
        if not target:
            for r,c,v in shape:
                result[r][c] = v
            continue
        tr, tc = target
        if tr == 0 or tr == rows - 1:
            dr = 0
            dc = tc - sc
        elif tc == 0 or tc == cols - 1:
            dr = tr - sr
            dc = 0
        else:
            dr = tr - sr
            dc = tc - sc
        for r, c, v in shape:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols:
                result[nr][nc] = v
    return result
